package routes

import (
	"io/fs"

	"github.com/codenomdev/viona/internal/modules/static"
	"github.com/codenomdev/viona/pkg/config"
	"github.com/codenomdev/viona/ui"
	"github.com/labstack/echo/v5"
)

type (
	UIRoutes struct {
		r *static.Routes
	}
)

func NewUIRoutes(
	r *static.Routes,
) *UIRoutes {
	return &UIRoutes{
		r: r,
	}
}

// Register a new static resource which generated by ui directory
func (a *UIRoutes) MapBaseStatic(e *echo.Echo, cfg *config.Config) {
	buildFS, err := fs.Sub(
		ui.Build,
		"build",
	)
	if err != nil {
		panic(err)
	}

	e.StaticFS(
		"/static",
		echo.MustSubFS(buildFS, "static"),
	)
	a.r.RegisterStatic(e, buildFS)
}
